from matplotlib import pyplot as pltfrom skimage import io, img_as_ubyte, img_as_float, data, measureimport cv2import numpy as npfrom skimage.color import label2rgb, rgb2grayimage = img_as_ubyte(rgb2gray(io.imread("../data/cast_iron.jpg")))from skimage.filters import threshold_otsu# Compute the optimal threshold value using Otsu's methodthreshold = threshold_otsu(image)# Create a binary image:# pixels below the threshold become True (foreground)# pixels above the threshold become False (background)binary_img = image < threshold# Label connected regions in the binary image# connectivity=image.ndim means:# - 2D image -> 8-connectivity# - 3D image -> full 3D connectivitylabel_img = measure.label(    binary_img,    connectivity=image.ndim)image_overlay = label2rgb(label_img,image)plt.imshow(image_overlay)# Measure properties of labeled regionsprops = measure.regionprops_table(    label_img,              # labeled image    image,                  # intensity image    properties=[        "label",            # region label number        "area",             # number of pixels in the region        "equivalent_diameter",  # diameter of a circle with same area        "solidity"          # compactness = area / convex hull area    ])import pandas as pddf = pd.DataFrame(props)print(df.head())